const ALLOWED_LANGS=["en","ru","hy"];let currentLangData=null;const prices={document:1,website:2,subtitles:3,certified:5,interpretation:10,other:0};async function setLanguage(e){if(!ALLOWED_LANGS.includes(e))return;const t=await fetch(`../../data/${e}.json`);if(!t.ok)return;const n=await t.json();document.getElementById("page-title").textContent=n.pageTitle,document.getElementById("page-description").textContent=n.pageDescription,document.getElementById("submit-button").textContent=n.submitButton,document.querySelectorAll("[data-i18n]").forEach(e=>{const t=e.dataset.i18n;n[t]&&(e.textContent=n[t])}),currentLangData=n,updateTotal()}function updateTotal(){const e=document.querySelectorAll('select[name="service[]"]');let t=0;e.forEach(e=>{t+=prices[e.value]||0});const n=currentLangData?.totalPrice||"Your total price is: $";document.getElementById("total-price").textContent=n+t}let requestCounter=1;function addRequest(){const e=document.getElementById("requests-container"),t=document.querySelector(".request-block").cloneNode(!0),n=++requestCounter;t.querySelectorAll("[id]").forEach(e=>e.removeAttribute("id"));const a=t.querySelector("select"),r=t.querySelector("textarea"),o=`service-${n}`,c=`description-${n}`;a.id=o,r.id=c,t.querySelector('label[data-i18n="labelService"]').setAttribute("for",o),t.querySelector('label[data-i18n="labelDescription"]').setAttribute("for",c),r.value="",a.selectedIndex=0,a.addEventListener("change",updateTotal);const d=t.querySelector(".request-buttons"),l=document.createElement("button");l.type="button",l.className="add-btn",l.textContent="+",l.addEventListener("click",addRequest);const u=document.createElement("button");for(u.type="button",u.className="remove-btn",u.textContent="−",u.addEventListener("click",()=>removeRequest(u));d.firstChild;)d.removeChild(d.firstChild);d.appendChild(l),d.appendChild(u),e.appendChild(t),updateTotal()}function removeRequest(e){e.closest(".request-block").remove(),updateTotal()}function validateAndSubmit(e){const t=document.querySelectorAll('textarea[name="description[]"]');Array.from(t).some(e=>e.value.trim())||(e.preventDefault(),alert(currentLangData?.validationError||"Please describe at least one request."))}window.addEventListener("load",()=>{setLanguage("en"),document.querySelectorAll(".lang-icon[data-lang]").forEach(e=>{e.addEventListener("click",()=>setLanguage(e.dataset.lang)),e.addEventListener("keydown",t=>{"Enter"!==t.key&&" "!==t.key||(t.preventDefault(),setLanguage(e.dataset.lang))})}),document.getElementById("request-form").addEventListener("submit",validateAndSubmit),document.querySelector(".request-buttons .add-btn").addEventListener("click",addRequest),document.querySelector('select[name="service[]"]').addEventListener("change",updateTotal)});